export default async function ({ execution_id }) {
  const r = await fetch('/platform/automation/v1/executions/' + execution_id + '/tasks/bedrock-command-status/result');
  const b = await r.json();
  const cmd = (b?.Commands || [])[0] || {};
  const s = (cmd.Status || '').toUpperCase();
  if (['PENDING','INPROGRESS','DELAYED'].includes(s)) throw new Error('Bedrock command still running: ' + s);
  if (['FAILED','CANCELLED','TIMED_OUT'].includes(s)) throw new Error('Bedrock command failed: ' + s);
  return b;
}

export default async function ({ execution_id }) {
  const r = await fetch('/platform/automation/v1/executions/' + execution_id + '/tasks/wait-for-remediation-completed/result');
  const b = await r.json();
  const status = (b?.AutomationExecution?.AutomationExecutionStatus || b?.AutomationExecutionStatus || '').toUpperCase();
  if (status !== 'SUCCESS') {
    throw new Error('Remediation automation failed with status: ' + status);
  }
  return b;
}
